  ('a68b3d31-07c5-4201-a5bb-8689337e77c6', 'Ich wiederhole die Vokabeln.', 'I review the vocabulary.', 'أراجع المفردات.', 'Used in Linguistik und Stilistik', 'neutral', false, NULL, 1),
  ('a68b3d31-07c5-4201-a5bb-8689337e77c6', 'Kannst du das bitte wiederholen?', 'Can you please repeat that?', 'هل يمكنك تكرار ذلك من فضلك؟', 'Used in Linguistik und Stilistik', 'formal', false, NULL, 2),
